func parseQueryParamEnum[T ~int32](s string) (T, error) {
	v, err := strconv.ParseInt(s, 10, 32)
	if err != nil {
		return 0, fmt.Errorf("invalid enum value: %w", err)
	}
	return T(v), nil
}
